const tx = $items('Create Transaction')[0].json;
const normalized = `search_query: ${tx.user_query.replace(/\s+/g, ' ').trim()}`;
return [{
  json: {
    ...tx,
    normalized_query: normalized,
    qdrant_collection: 'tpm_unite_history'
  }
}];

const tx = $items('Create Transaction')[0].json;
const normalized = $items('Normalize Query')[0].json.normalized_query;
const response = $json;
const statusCode = response.statusCode ?? response.status ?? 0;
const collectionExists = statusCode >= 200 && statusCode < 300 && !!response.body?.result;

return [{
  json: {
    transaction_id: tx.transaction_id,
    user_query: tx.user_query,
    normalized_query: normalized,
    qdrant_collection: 'tpm_unite_history',
    qdrant_status_code: statusCode,
    collection_exists: collectionExists,
    retrieval_decision: collectionExists ? 'collection_available' : 'qdrant_collection_missing',
    next_status: collectionExists ? 'retrieving' : 'refused',
    next_retrieval_status: collectionExists ? 'not_started' : 'no_context',
    refusal_reason: collectionExists ? null : 'qdrant_collection_missing'
  }
}];
